{
  "openapi": "3.0.0",
  "info": {
    "title": "Corporate ERP Inventory Check",
    "version": "1.0.0",
    "description": "Response schema for an inventory check including warehouse metadata, product specs, and stock levels across regions"
  },
  "components": {
    "schemas": {
      "Address": {
        "type": "object",
        "description": "Physical address details of the warehouse",
        "properties": {
          "street": {
            "type": "string",
            "description": "Street address",
            "example": "1234 Commerce St"
          },
          "city": {
            "type": "string",
            "description": "City name",
            "example": "Metropolis"
          },
          "state": {
            "type": "string",
            "description": "State or province",
            "example": "NY"
          },
          "postal_code": {
            "type": "string",
            "description": "Postal or ZIP code",
            "example": "10101"
          },
          "country": {
            "type": "string",
            "description": "Country name",
            "example": "USA"
          }
        },
        "required": ["street", "city", "state", "postal_code", "country"]
      },
      "Warehouse": {
        "type": "object",
        "description": "Metadata about the warehouse location",
        "properties": {
          "id": {
            "type": "string",
            "description": "Unique identifier for the warehouse",
            "example": "wh_007"
          },
          "name": {
            "type": "string",
            "description": "Name of the warehouse",
            "example": "Central Distribution Center"
          },
          "address": {
            "$ref": "#/components/schemas/Address"
          }
        },
        "required": ["id", "name", "address"]
      },
      "Dimensions": {
        "type": "object",
        "description": "Physical dimensions of the product",
        "properties": {
          "length": {
            "type": "number",
            "format": "float",
            "description": "Length in centimeters",
            "example": 15.0
          },
          "width": {
            "type": "number",
            "format": "float",
            "description": "Width in centimeters",
            "example": 4.5
          },
          "height": {
            "type": "number",
            "format": "float",
            "description": "Height in centimeters",
            "example": 3.0
          }
        },
        "required": ["length", "width", "height"]
      },
      "TechnicalSpecs": {
        "type": "object",
        "description": "Technical specifications detailing product attributes",
        "properties": {
          "weight_kg": {
            "type": "number",
            "format": "float",
            "description": "Weight in kilograms",
            "example": 0.75
          },
          "dimensions_cm": {
            "$ref": "#/components/schemas/Dimensions"
          },
          "material": {
            "type": "string",
            "description": "Primary material of the product",
            "example": "Stainless Steel"
          },
          "warranty_months": {
            "type": "integer",
            "description": "Warranty duration in months",
            "example": 24
          }
        },
        "required": ["weight_kg", "dimensions_cm", "material", "warranty_months"]
      },
      "StockLevels": {
        "type": "object",
        "description": "Stock availability counts across multiple regions",
        "properties": {
          "north_america": {
            "type": "integer",
            "description": "Stock count in North America",
            "example": 150
          },
          "europe": {
            "type": "integer",
            "description": "Stock count in Europe",
            "example": 80
          },
          "asia": {
            "type": "integer",
            "description": "Stock count in Asia",
            "example": 120
          }
        },
        "required": ["north_america", "europe", "asia"]
      },
      "ProductInventory": {
        "type": "object",
        "description": "Inventory details per product",
        "properties": {
          "product_id": {
            "type": "string",
            "description": "Unique identifier for the product",
            "example": "prd_1001"
          },
          "product_name": {
            "type": "string",
            "description": "Official product name",
            "example": "MultiTool Pro"
          },
          "technical_specs": {
            "$ref": "#/components/schemas/TechnicalSpecs"
          },
          "stock_levels": {
            "$ref": "#/components/schemas/StockLevels"
          }
        },
        "required": ["product_id", "product_name", "technical_specs", "stock_levels"]
      },
      "InventoryResponse": {
        "type": "object",
        "description": "Root response containing warehouse info and product inventories",
        "properties": {
          "warehouse": {
            "$ref": "#/components/schemas/Warehouse"
          },
          "inventory": {
            "type": "array",
            "description": "List of products with inventory details",
            "items": {
              "$ref": "#/components/schemas/ProductInventory"
            },
            "example": [
              {
                "product_id": "prd_1001",
                "product_name": "MultiTool Pro",
                "technical_specs": {
                  "weight_kg": 0.75,
                  "dimensions_cm": {
                    "length": 15.0,
                    "width": 4.5,
                    "height": 3.0
                  },
                  "material": "Stainless Steel",
                  "warranty_months": 24
                },
                "stock_levels": {
                  "north_america": 150,
                  "europe": 80,
                  "asia": 120
                }
              },
              {
                "product_id": "prd_1002",
                "product_name": "UltraFast SSD 1TB",
                "technical_specs": {
                  "weight_kg": 0.05,
                  "dimensions_cm": {
                    "length": 7.0,
                    "width": 5.0,
                    "height": 0.7
                  },
                  "material": "Aluminum",
                  "warranty_months": 36
                },
                "stock_levels": {
                  "north_america": 300,
                  "europe": 220,
                  "asia": 400
                }
              }
            ]
          }
        },
        "required": ["warehouse", "inventory"]
      }
    }
  }
}

