{
  "openapi": "3.0.0",
  "info": { "title": "Cybersecurity Threat Intelligence Alert", "version": "1.0.0" },
  "components": {
    "schemas": {
      "AttackVector": {
        "type": "string",
        "description": "Descrição do vetor de ataque identificado",
        "example": "DDoS"
      },
      "AffectedIP": {
        "type": "object",
        "description": "Endereço IP afetado e os vetores de ataque associados",
        "properties": {
          "ip_address": {
            "type": "string",
            "description": "Endereço IP identificado como afetado",
            "example": "192.168.1.1"
          },
          "attack_vectors": {
            "type": "array",
            "description": "Lista de vetores de ataque associados a este IP",
            "items": { "$ref": "#/components/schemas/AttackVector" },
            "example": ["DDoS", "Phishing"]
          }
        }
      },
      "ThreatAlert": {
        "type": "object",
        "description": "Alerta contendo o nível de severidade, IPs afetados e protocolos de mitigação recomendados",
        "properties": {
          "severity_level": {
            "type": "string",
            "description": "Nível de severidade da ameaça",
            "example": "High"
          },
          "affected_ips": {
            "type": "array",
            "description": "Lista de endereços IP afetados pela ameaça",
            "items": { "$ref": "#/components/schemas/AffectedIP" },
            "example": [
              { "ip_address": "192.168.1.1", "attack_vectors": ["DDoS", "Phishing"] },
              { "ip_address": "10.0.0.5", "attack_vectors": ["Malware", "Brute Force"] }
            ]
          },
          "mitigation_protocols": {
            "type": "array",
            "description": "Protocolos recomendados para mitigação da ameaça",
            "items": { "type": "string" },
            "example": ["Update firewall rules", "Conduct user training", "Apply software patches"]
          }
        }
      }
    }
  }
}

