const AddressSchema = z.object({
  street: z.string().openapi({ description: 'Street name and building number', example: '456 Olive Garden Way' }),
  city: z.string().openapi({ description: 'City name', example: 'New York' }),
  postal_code: z.string().openapi({ description: 'Postal or ZIP code', example: '10001' })
}).openapi({ title: 'Address', description: 'Physical location details' });

const RestaurantSchema = z.object({
  id: z.string().openapi({ description: 'Unique identifier for the restaurant', example: 'rest_990' }),
  name: z.string().openapi({ description: 'Display name of the restaurant', example: 'Pasta Paradiso' }),
  rating: z.number().openapi({ description: 'Average customer rating from 1 to 5', example: 4.8 }),
  cuisine_type: z.string().openapi({ description: 'Primary cuisine category', example: 'Italian' }),
  address: AddressSchema
}).openapi({ title: 'Restaurant Profile', description: 'Detailed information about the merchant' });

const LocationSchema = z.object({
  latitude: z.number().openapi({ description: 'Current latitude coordinate', example: 40.7128 }),
  longitude: z.number().openapi({ description: 'Current longitude coordinate', example: -74.006 }),
  speed_kmh: z.number().openapi({ description: 'Current travel speed in kilometers per hour', example: 22.4 }),
  last_updated: z.string().datetime().openapi({ description: 'ISO 8601 timestamp of the last GPS update', example: '2023-10-27T18:15:00Z' })
}).openapi({ title: 'Courier Location', description: 'Real-time GPS tracking data for the courier' });

const DishSchema = z.object({
  id: z.string().openapi({ description: 'Unique identifier for the dish', example: 'item_001' }),
  name: z.string().openapi({ description: 'Name of the food item', example: 'Spaghetti Carbonara' }),
  price: z.number().openapi({ description: 'Price per unit', example: 18.0 }),
  quantity: z.number().int().openapi({ description: 'Number of units ordered', example: 1 }),
  dietary_notes: z.array(z.string()).openapi({ description: 'List of special dietary requirements or instructions', example: ['No black pepper', 'Extra parmesan'] })
}).openapi({ title: 'Dish Item', description: 'Specific details of an ordered food item' });

export const OrderStatusSchema = z.object({
  order_id: z.string().openapi({ description: 'Unique order tracking number', example: 'ord_772194' }),
  status: z.enum(['preparing', 'ready_for_pickup', 'out_for_delivery', 'delivered', 'cancelled']).openapi({ description: 'Current fulfillment status of the order', example: 'out_for_delivery' }),
  total_amount: z.number().openapi({ description: 'Total cost of the order including taxes and fees', example: 42.5 }),
  estimated_delivery_time: z.string().datetime().openapi({ description: 'Expected time of arrival at the customer location', example: '2023-10-27T18:45:00Z' }),
  courier_location: LocationSchema,
  restaurant: RestaurantSchema,
  items: z.array(DishSchema).openapi({ description: 'Collection of all items included in this order', minItems: 1 })
}).openapi({ title: 'Order Status Update', description: 'Comprehensive real-time status of a food delivery order' });

