import { z } from 'zod';
import { extendZodWithOpenApi } from '@asteasolutions/zod-to-openapi';

extendZodWithOpenApi(z);

const DietaryRestrictionSchema = z.object({
  type: z.string().openapi({
    description: 'O tipo de restrição ou alergia alimentar',
    example: 'Glúten'
  }),
  severity: z.enum(['mild', 'moderate', 'severe']).openapi({
    description: 'O nível de gravidade da restrição para a equipe de cozinha',
    example: 'severe'
  })
}).openapi({ description: 'Detalhes de uma restrição alimentar específica' });

const CustomerSchema = z.object({
  full_name: z.string().openapi({
    description: 'Nome completo do cliente que realizou a reserva',
    example: 'Beatriz Oliveira'
  }),
  email: z.string().email().openapi({
    description: 'Endereço de e-mail para confirmação e notificações',
    example: 'beatriz.oliveira@exemplo.com.br'
  }),
  dietary_restrictions: z.array(DietaryRestrictionSchema).openapi({
    description: 'Lista de todas as restrições alimentares informadas pelo cliente',
    example: [{ type: 'Glúten', severity: 'severe' }]
  })
}).openapi({ description: 'Informações de contato e perfil de saúde do cliente' });

const PreOrderItemSchema = z.object({
  item_id: z.string().openapi({
    description: 'Identificador único do item conforme o cardápio',
    example: 'menu_item_502'
  }),
  name: z.string().openapi({
    description: 'Nome descritivo do prato ou bebida',
    example: 'Risoto de Cogumelos Trufado'
  }),
  quantity: z.number().int().positive().openapi({
    description: 'Quantidade de unidades do item solicitado',
    example: 2
  }),
  special_instructions: z.string().nullable().openapi({
    description: 'Observações adicionais para o preparo do item',
    example: 'Sem manteiga, por favor.'
