  bitrate_kbps: z.number().int().openapi({ description: 'Audio bitrate in kilobits per second', example: 320 }),
  sample_rate_hz: z.number().int().openapi({ description: 'Audio sample rate in Hertz', example: 44100 }),
  format: z.enum(['MP3', 'FLAC', 'WAV', 'AAC']).openapi({ description: 'The audio file format', example: 'FLAC' }),
  channels: z.number().int().openapi({ description: 'Number of audio channels', example: 2 }),
