  id: z.string().openapi({ description: 'Unique identifier of the driver', example: 'DRV-441' }),
  name: z.string().openapi({ description: 'Full name of the driver', example: 'Jonathan Miller' }),
  license_number: z.string().openapi({ description: 'Driver license identification number', example: 'DL-CA-992011' }),
  contact: z.string().openapi({ description: 'Contact phone number in international format', example: '+1-555-010-8899' }),
}).openapi({ description: 'Driver personal and professional information' });

