  country: z.string().openapi({ description: 'ISO 3166-1 alpha-3 country code', example: 'USA' }),
}).openapi({ description: 'Physical shipping address details' });

const ItemDimensionsSchema = z.object({
  weight_kg: z.number().positive().openapi({ description: 'Weight of the item in kilograms', example: 0.05 }),
  length_cm: z.number().positive().openapi({ description: 'Length of the item in centimeters', example: 15.0 }),
  width_cm: z.number().positive().openapi({ description: 'Width of the item in centimeters', example: 1.0 }),
  height_cm: z.number().positive().openapi({ description: 'Height of the item in centimeters', example: 1.0 }),
}).openapi({ description: 'Physical dimensions of a product' });

const OrderItemSchema = z.object({
  product_id: z.string().openapi({ description: 'Unique identifier of the product', example: 'prod_001' }),
  sku: z.string().openapi({ description: 'Stock Keeping Unit identifier', example: 'WPN-PENCIL-01' }),
  name: z.string().openapi({ description: 'Display name of the product', example: 'Tactical Graphite Pencil' }),
  quantity: z.number().int().positive().openapi({ description: 'Number of units ordered', example: 12 }),
  unit_price: z.number().openapi({ description: 'Price per single unit', example: 2.5 }),
  total_price: z.number().openapi({ description: 'Total price for this line item', example: 30.0 }),
  dimensions: ItemDimensionsSchema,
}).openapi({ description: 'Individual item within an order' });

const PaymentDetailsSchema = z.object({
  transaction_id: z.string().openapi({ description: 'Unique payment gateway transaction ID', example: 'txn_8833221100' }),
  method: z.enum(['credit_card', 'paypal', 'bank_transfer', 'crypto']).openapi({ description: 'Payment method used', example: 'credit_card' }),
  status: z.enum(['pending', 'authorized', 'captured', 'refunded', 'failed']).openapi({ description: 'Current state of the payment', example: 'captured' }),
  amount: z.number().openapi({ description: 'Total amount charged', example: 1255.5 }),
  currency: z.string().length(3).openapi({ description: 'ISO 4217 currency code', example: 'USD' }),
