}).openapi({ description: 'Financial transaction details' });

const OrderTotalsSchema = z.object({
  subtotal: z.number().openapi({ description: 'Sum of item prices before tax and shipping', example: 1230.0 }),
  tax: z.number().openapi({ description: 'Total tax applied to the order', example: 15.5 }),
  shipping_cost: z.number().openapi({ description: 'Cost of shipping and handling', example: 10.0 }),
  grand_total: z.number().openapi({ description: 'Final amount paid by the customer', example: 1255.5 }),
}).openapi({ description: 'Order financial summary' });

const HalLinkSchema = z.object({
  href: z.string().url().openapi({ description: 'The absolute or relative URL of the resource', example: '/api/v1/orders/ord_77219405x' }),
}).openapi({ description: 'HAL-compliant hyperlink' });

const HalLinksSchema = z.record(z.string(), HalLinkSchema).openapi({ description: 'Collection of HAL links for resource navigation' });

export const OrderResponseSchema = z.object({
  order_id: z.string().openapi({ description: 'Unique order identifier', example: 'ord_77219405x' }),
  customer: z.object({
    customer_id: z.string().openapi({ description: 'Unique customer identifier', example: 'cust_9921' }),
    full_name: z.string().openapi({ description: 'Customer full legal name', example: 'Jonathan Wick' }),
    email: z.string().email().openapi({ description: 'Customer contact email', example: 'j.wick@continental.com' }),
  }).openapi({ description: 'Customer basic information' }),
  status: z.enum(['pending', 'processing', 'shipped', 'delivered', 'cancelled']).openapi({ description: 'Current fulfillment status of the order', example: 'shipped' }),
  items: z.array(OrderItemSchema).openapi({ description: 'List of physical products in the order' }),
  shipping_address: AddressSchema,
  payment: PaymentDetailsSchema,
  totals: OrderTotalsSchema,
  _links: HalLinksSchema,
}).openapi({ title: 'Order Response', description: 'Detailed response containing order fulfillment and payment data' });

