        "type": "object",
        "description": "A physical copy of the book with location and status",
        "properties": {
          "copy_id": {
            "type": "string",
            "description": "Unique identifier for the book copy",
            "example": "copy_001"
          },
          "shelf_location": {
            "type": "string",
            "description": "Current shelf location of the copy in the library",
            "example": "Aisle 3, Shelf 2"
          },
          "status": {
            "type": "string",
            "description": "Current borrowing status of the copy",
            "example": "available"
          }
        },
        "required": ["copy_id", "shelf_location", "status"]
      },
      "DigitalAvailability": {
        "type": "object",
        "description": "Information about digital borrowing availability for the book",
        "properties": {
          "is_available": {
            "type": "boolean",
            "description": "Whether the book is available for digital borrowing",
            "example": true
          },
          "borrow_url": {
            "type": "string",
            "format": "uri",
            "description": "URL to borrow the digital version of the book",
            "example": "https://library.example.com/borrow/978-3-16-148410-0"
          }
        },
        "required": ["is_available", "borrow_url"]
      },
      "BookSearchResult": {
        "type": "object",
        "description": "Result of a book search including metadata, physical copies, and digital availability",
        "properties": {
          "isbn": {
            "type": "string",
            "description": "International Standard Book Number of the book",
            "example": "978-3-16-148410-0"
          },
          "title": {
            "type": "string",
            "description": "Title of the book",
            "example": "Introduction to OpenAPI"
          },
          "author": {
            "type": "string",
            "description": "Author of the book",
            "example": "Jane Doe"
          },
          "copies": {
            "type": "array",
            "description": "List of physical copies available in the library",
            "items": {
              "$ref": "#/components/schemas/Copy"
            }
          },
          "digital_availability": {
            "$ref": "#/components/schemas/DigitalAvailability"
          }
        },
        "required": ["isbn", "title", "author", "copies", "digital_availability"]
      }
    }
  }
}

