import { z } from 'zod';
import { extendZodWithOpenApi } from '@asteasolutions/zod-to-openapi';

extendZodWithOpenApi(z);

const GearStatsSchema = z.record(z.number()).openapi({
  description: 'Mapa de atributos numéricos do item (ex: defesa, ataque)',
  example: { defense: 150, magic_resistance: 45 }
});

const GearItemSchema = z.object({
  item_id: z.string().openapi({ description: 'Identificador único do item de equipamento', example: 'itm_h102' }),
  name: z.string().openapi({ description: 'Nome exibido do item', example: 'Elmo do Guardião Eterno' }),
  rarity: z.enum(['Common', 'Uncommon', 'Rare', 'Epic', 'Legendary']).openapi({ description: 'Grau de raridade do item', example: 'Legendary' }),
  stats: GearStatsSchema
}).openapi({ description: 'Detalhes de um item de equipamento individual' });

const EquippedGearSchema = z.object({
  head: GearItemSchema.openapi({ description: 'Item equipado no slot da cabeça' }),
  chest: GearItemSchema.openapi({ description: 'Item equipado no slot do peito' }),
  weapon: GearItemSchema.openapi({ description: 'Item equipado no slot da arma' })
}).openapi({ description: 'Conjunto de equipamentos atualmente equipados pelo jogador' });

const AchievementSchema = z.object({
  achievement_id: z.string().openapi({ description: 'Identificador único da conquista', example: 'ach_001' }),
  title: z.string().openapi({ description: 'Título da conquista desbloqueada', example: 'Primeiros Passos' }),
  unlocked_at: z.string().datetime().openapi({ description: 'Data e hora do desbloqueio no formato ISO 8601', example: '2023-01-15T10:30:00Z' })
}).openapi({ description: 'Registro de uma conquista desbloqueada' });

export const PlayerProfileSchema = z.object({
  player_id: z.string().openapi({ description: 'Identificador único global do jogador', example: 'plr_882341' }),
  username: z.string().openapi({ description: 'Nome de usuário escolhido pelo jogador', example: 'ShadowSlayer_99' }),
