const IPAddressSchema = z.object({
  ip: z.string().ip().openapi({ description: 'Endereço IP afetado pela ameaça', example: '192.168.1.105' }),
  port: z.number().int().positive().openapi({ description: 'Porta de rede envolvida no incidente', example: 443 }),
  protocol: z.enum(['TCP', 'UDP', 'ICMP']).openapi({ description: 'Protocolo de rede utilizado no ataque', example: 'TCP' }),
  last_seen: z.string().datetime().openapi({ description: 'Data e hora da última detecção do IP', example: '2023-10-27T15:40:00Z' }),
}).openapi({ title: 'Endereço IP Afetado', description: 'Detalhes técnicos de um endereço IP sob ataque' });

const MitigationProtocolSchema = z.object({
  id: z.string().openapi({ description: 'Identificador único do protocolo de mitigação', example: 'MIT-001' }),
  action: z.string().openapi({ description: 'Ação técnica recomendada para conter a ameaça', example: 'IP Blacklisting' }),
  priority: z.enum(['immediate', 'high', 'medium', 'low']).openapi({ description: 'Nível de urgência para execução da ação', example: 'immediate' }),
  description: z.string().openapi({ description: 'Descrição detalhada de como implementar a mitigação', example: 'Bloquear todo o tráfego originado dos IPs afetados no firewall de borda.' }),
}).openapi({ title: 'Protocolo de Mitigação', description: 'Instruções para resposta a incidentes' });

const MetadataSchema = z.object({
  source_system: z.string().openapi({ description: 'Sistema ou sensor que gerou o alerta', example: 'Sentinel-IDS-v4' }),
  confidence_score: z.number().min(0).max(1).openapi({ description: 'Nível de confiança da detecção, variando de 0 a 1', example: 0.98 }),
}).openapi({ title: 'Metadados do Alerta', description: 'Informações contextuais sobre a origem e confiabilidade do alerta' });

export const ThreatIntelligenceAlertSchema = z.object({
  alert_id: z.string().uuid().openapi({ description: 'Identificador único universal (UUID) do alerta de ameaça', example: 'a1b2c3d4-e5f6-4g7h-8i9j-k0l1m2n3o4p5' }),
  timestamp: z.string().datetime().openapi({ description: 'Data e hora em que o alerta foi emitido', example: '2023-10-27T15:45:00Z' }),
  threat_type: z.string().openapi({ description: 'Classificação do tipo de ameaça detectada', example: 'Distributed Denial of Service (DDoS)' }),
  severity: z.enum(['low', 'medium', 'high', 'critical']).openapi({ description: 'Nível de severidade do incidente de segurança', example: 'critical' }),
  affected_ips: z.array(IPAddressSchema).openapi({ description: 'Lista de endereços IP que foram identificados como parte do ataque' }),
  mitigation_protocols: z.array(MitigationProtocolSchema).openapi({ description: 'Conjunto de protocolos recomendados para resposta imediata' }),
  metadata: MetadataSchema.openapi({ description: 'Informações adicionais de contexto e confiança' }),
}).openapi({ 
  title: 'Alerta de Inteligência de Ameaças Cibernéticas', 
  description: 'Esquema detalhado para alertas de segurança contendo severidade, IPs afetados e protocolos de mitigação.' 
});

