import { z } from 'zod';
import { extendZodWithOpenApi } from '@asteasolutions/zod-to-openapi';

extendZodWithOpenApi(z);

const PaginationSchema = z.object({
  current_page: z.number().int().openapi({ description: 'The current page number', example: 1 }),
  total_pages: z.number().int().openapi({ description: 'Total number of pages available', example: 10 }),
  total_results: z.number().int().openapi({ description: 'Total number of books matching the search criteria', example: 100 }),
  page_size: z.number().int().openapi({ description: 'Number of items per page', example: 20 })
}).openapi({ description: 'Pagination metadata for search results' });

const ISBNMetadataSchema = z.object({
  isbn_10: z.string().openapi({ description: 'The 10-digit International Standard Book Number', example: '020161622X' }),
  isbn_13: z.string().openapi({ description: 'The 13-digit International Standard Book Number', example: '978-0201616224' }),
  publisher: z.string().openapi({ description: 'The publishing house name', example: 'Addison-Wesley Professional' }),
  published_year: z.number().int().openapi({ description: 'The year the book was published', example: 1999 })
}).openapi({ description: 'Standardized book identification metadata' });

const ShelfLocationSchema = z.object({
  aisle: z.string().openapi({ description: 'The aisle identifier in the library', example: 'A12' }),
  section: z.string().openapi({ description: 'The specific section code', example: 'CS-04' }),
  shelf: z.string().openapi({ description: 'The shelf number or level', example: '3' })
}).openapi({ description: 'Physical coordinates of a book in the library' });

const PhysicalCopySchema = z.object({
  copy_id: z.string().openapi({ description: 'Unique identifier for the physical copy', example: 'cp_001' }),
  status: z.enum(['available', 'borrowed', 'reserved', 'maintenance']).openapi({ description: 'Current availability status of the copy', example: 'available' }),
  location: ShelfLocationSchema.openapi({ description: 'Physical location of the copy' }),
  due_date: z.string().datetime().optional().openapi({ description: 'Expected return date if the book is borrowed', example: '2023-12-15T10:00:00Z' })
}).openapi({ description: 'Details of a specific physical book instance' });

const DigitalFormatSchema = z.object({
  type: z.enum(['PDF', 'EPUB', 'MOBI']).openapi({ description: 'The digital file format', example: 'PDF' }),
  file_size: z.string().openapi({ description: 'The size of the digital file', example: '12MB' }),
  access_url: z.string().url().openapi({ description: 'Secure URL to access or download the digital copy', example: 'https://lib.example.com/download/bk_98234/pdf' })
}).openapi({ description: 'Digital file specification' });

const DigitalAvailabilitySchema = z.object({
  is_available: z.boolean().openapi({ description: 'Whether the book is available for digital borrowing', example: true }),
  formats: z.array(DigitalFormatSchema).openapi({ description: 'List of available digital formats' })
}).openapi({ description: 'Digital access and borrowing status' });

const BookLinksSchema = z.object({
  self: z.string().url().openapi({ description: 'API endpoint for the book details', example: '/api/v1/books/bk_98234' }),
  reserve: z.string().url().openapi({ description: 'API endpoint to place a reservation request', example: '/api/v1/books/bk_98234/reserve' })
}).openapi({ description: 'HATEOAS links for book operations' });

const BookSchema = z.object({
  book_id: z.string().openapi({ description: 'Unique internal book identifier', example: 'bk_98234' }),
  title: z.string().openapi({ description: 'Full title of the book', example: 'The Pragmatic Programmer' }),
  author: z.string().openapi({ description: 'Full name(s) of the author(s)', example: 'Andrew Hunt, David Thomas' }),
  isbn_metadata: ISBNMetadataSchema.openapi({ description: 'ISBN and publishing details' }),
  physical_copies: z.array(PhysicalCopySchema).openapi({ description: 'List of all physical copies in the system' }),
  digital_availability: DigitalAvailabilitySchema.openapi({ description: 'Digital borrowing options' })
}).merge(BookLinksSchema).openapi({ description: 'A comprehensive book search result entity' });

export const BookSearchResponseSchema = z.object({
  results: z.array(BookSchema).openapi({ description: 'List of books matching the search query' }),
  pagination: PaginationSchema.openapi({ description: 'Pagination details for the result set' })
}).openapi({ title: 'Book Search Response', description: 'Response schema for the library book search API' });

