import { z } from 'zod';
import { extendZodWithOpenApi } from '@asteasolutions/zod-to-openapi';

extendZodWithOpenApi(z);

const SeverityEnum = z.enum(['Low', 'Medium', 'High', 'Critical']).openapi({
  description: 'Nível de gravidade da ameaça detectada',
  example: 'Critical'
});

const AffectedAssetSchema = z.object({
  ip_address: z.string().ip().openapi({ description: 'Endereço IP do ativo afetado', example: '192.168.1.45' }),
  hostname: z.string().openapi({ description: 'Nome de rede do host comprometido', example: 'srv-prod-db-01' }),
  location: z.string().openapi({ description: 'Localização física ou lógica do ativo', example: 'São Paulo, BR' }),
  risk_score: z.number().min(0).max(100).openapi({ description: 'Pontuação de risco calculada (0-100)', example: 98.5 })
}).openapi({ description: 'Detalhes do ativo de rede afetado' });

const MitigationStepSchema = z.object({
  step_order: z.number().int().positive().openapi({ description: 'Ordem sequencial de execução do protocolo', example: 1 }),
  action: z.string().openapi({ description: 'Descrição detalhada da ação de mitigação', example: 'Isolar VLANs afetadas da rede core' }),
  priority: z.string().openapi({ description: 'Prioridade de execução da etapa', example: 'Immediate' }),
  documentation_url: z.string().url().openapi({ description: 'Link para a documentação técnica do procedimento', example: 'https://wiki.internal/security/isolation-proc' })
}).openapi({ description: 'Etapa individual de um protocolo de mitigação' });

const AlertMetadataSchema = z.object({
  source: z.string().openapi({ description: 'Fonte da inteligência de ameaças', example: 'CrowdStrike Falcon' }),
  confidence_level: z.number().min(0).max(100).openapi({ description: 'Nível de confiança da detecção (0-100%)', example: 95 }),
  tags: z.array(z.string()).openapi({ description: 'Etiquetas de categorização da ameaça', example: ['malware', 'lateral-movement'] })
}).openapi({ description: 'Metadados adicionais do alerta de segurança' });

export const ThreatIntelligenceAlertSchema = z.object({
  alert_id: z.string().uuid().openapi({ description: 'Identificador único universal do alerta', example: 'alert-99283-xqz' }),
  timestamp: z.string().datetime().openapi({ description: 'Data e hora da detecção em formato ISO 8601', example: '2023-10-27T14:30:00Z' }),
  severity: SeverityEnum,
  threat_type: z.string().openapi({ description: 'Classificação do tipo de ameaça', example: 'Ransomware Propagation' }),
