  route_stops: z.array(StopSchema).openapi({ description: 'Lista sequencial de paradas programadas para a rota' }),
  last_updated: z.string().datetime().openapi({ description: 'Data e hora da última atualização de telemetria recebida', example: '2023-10-27T10:15:30Z' })
}).openapi({ title: 'Rastreamento de Frota', description: 'Resposta detalhada com a posição e status de um veículo de entrega' });
